    [OSStructureField(Description = "A list of [Envelope ID tabs][envelopeId]. An Envelope ID tab  displays the envelope ID. Recipients cannot enter or change the information in this tab. This value can't be set. [envelopeId]: /docs/esign-rest-api/reference/envelopes/enveloperecipienttabs/create/#response201_envelopeid", OriginalName = "envelopeIdTabs")]
