    [OSStructureField(Description = "A list of [Checkbox tabs][checkbox]. A Checkbox tab enables the recipient to select a yes/no (on/off) option. This value can be set. [checkbox]:  /docs/esign-rest-api/reference/envelopes/enveloperecipienttabs/", OriginalName = "checkboxTabs")]
    public List<Checkbox> CheckboxTabs { get; set; }

    [OSStructureField(Description = "An array of tabs that represents a collection of comments in a comment thread. For example, if a recipient has questions about the content of a document, they can add a comment to the document and control who else can see the comment. This value can't be set.", OriginalName = "commentThreadTabs")]
    public List<CommentThread> CommentThreadTabs { get; set; }

    [OSStructureField(Description = "A list of [Commission County tabs][cc]. A Commission County tab displays the county of a notary's commission. This tab can only be assigned to a remote notary recipient using [Docusign Notary][notary]. The tab's value can be edited by the recipient. [cc]:  /docs/esign-rest-api/reference/envelopes/enveloperecipienttabs/ [notary]: /docs/notary-api/", OriginalName = "commissionCountyTabs")]
    public List<CommissionCounty> CommissionCountyTabs { get; set; }

    [OSStructureField(Description = "A list of [Commission Expiration tabs][tabref]. A Commission Expiration tab displays the expiration date of a notary's commission. This tab can only be assigned to a remote notary recipient using [Docusign Notary][notary]. The tab's value can be edited by the recipient. [tabref]:  /docs/esign-rest-api/reference/envelopes/enveloperecipienttabs/ [notary]: /docs/notary-api/", OriginalName = "commissionExpirationTabs")]
    public List<CommissionExpiration> CommissionExpirationTabs { get; set; }

    [OSStructureField(Description = "A list of [Commission Number tabs][tabref]. A Commission Number tab displays a notary's commission number. This tab can only be assigned to a remote notary recipient using [Docusign Notary][notary]. The tab's value can be edited by the recipient. [tabref]:  /docs/esign-rest-api/reference/envelopes/enveloperecipienttabs/ [notary]: /docs/notary-api/", OriginalName = "commissionNumberTabs")]
    public List<CommissionNumber> CommissionNumberTabs { get; set; }

    [OSStructureField(Description = "A list of [Commission State tabs][cc]. A Commission County tab displays the state in which a notary's commission was granted. This tab can only be assigned to a remote notary recipient using [Docusign Notary][notary]. The tab's value can be edited by the recipient. [cc]:  /docs/esign-rest-api/reference/envelopes/enveloperecipienttabs/ [notary]: /docs/notary-api/", OriginalName = "commissionStateTabs")]
    public List<CommissionState> CommissionStateTabs { get; set; }

    [OSStructureField(Description = "A list of [Company tabs][company]. A Company tab displays a field for the name of the recipient's company. This value can't be set. [company]: /docs/esign-rest-api/reference/envelopes/enveloperecipienttabs/create/#parameters_company", OriginalName = "companyTabs")]
    public List<Company> CompanyTabs { get; set; }

    [OSStructureField(Description = "A list of [Date Signed tabs][dateSigned]. A Date Signed tab displays the date that the recipient signed the document. This value can't be set. [dateSigned]: /docs/esign-rest-api/reference/envelopes/enveloperecipienttabs/", OriginalName = "dateSignedTabs")]
    public List<DateSigned> DateSignedTabs { get; set; }

    [OSStructureField(Description = "A list of Date tabs. A Date tab enables the recipient to enter a date either by typing or using a date-picker. If you provide a `value` for this tab, it becomes read-only. The tooltip shown to the signer will always show MM/DD/YYYY, but you can specify three different [regular expression](https://en.wikipedia.org/wiki/Regular_expression) (regex) validation patterns for the date by setting the `validationPattern` property. Your three choices are: * DD/MM/YYYY: (((0[1-9])|([12][0-9])|(3[01]))) * MM/DD/YYYY: (((|0)[1-9]|1[0-2])/((|0)[1-9]|[1-2][0-9]|3[0-1])/[0-9]{4}$) * YYYY/DD/MM: ([0-9]{4}/((|0)[1-9]|1[0-2])/((|0)[1-9]|[1-2][0-9]|3[0-1])", OriginalName = "dateTabs")]
    public List<Date> DateTabs { get; set; }

    [OSStructureField(Description = "A list of [Decline tabs][decline]. A Decline tab enables the recipient to decline the envelope. If the recipient clicks the tab during the signing process, the envelope is voided. The value of this tab can't be set. [decline]: /docs/esign-rest-api/reference/envelopes/enveloperecipienttabs/", OriginalName = "declineTabs")]
    public List<Decline> DeclineTabs { get; set; }

    [OSStructureField(Description = "A list of Draw Tabs. A Draw Tab allows the recipient to add a free-form drawing to the document.", OriginalName = "drawTabs")]
    public List<Draw> DrawTabs { get; set; }

    [OSStructureField(Description = "A list of [Email Address tabs][emailAddress]. An Email Address tab displays the recipient's email as entered in the recipient information. This value can't be set. [emailAddress]: /docs/esign-rest-api/reference/envelopes/enveloperecipienttabs/", OriginalName = "emailAddressTabs")]
    public List<EmailAddress> EmailAddressTabs { get; set; }

    [OSStructureField(Description = "A list of [Email tabs][email]. An Email tab enables the recipient to enter an email address. This is a one-line field that checks that a valid email address is entered. It uses the same parameters as a Text tab, with the validation message and pattern set for email information. This value can be set. When getting information that includes this tab type, the original value of the tab when the associated envelope was sent is included in the response. [email]: /docs/esign-rest-api/reference/envelopes/enveloperecipienttabs/", OriginalName = "emailTabs")]
    public List<Email> EmailTabs { get; set; }

    [OSStructureField(Description = "A list of [Envelope ID tabs][envelopeId]. An Envelope ID tab  displays the envelope ID. Recipients cannot enter or change the information in this tab. This value can't be set. [envelopeId]: /docs/esign-rest-api/reference/envelopes/enveloperecipienttabs/create/#response201_envelopeid", OriginalName = "envelopeIdTabs")]
    public List<EnvelopeId> EnvelopeIdTabs { get; set; }

    [OSStructureField(Description = "A list of [First Name tabs][firstName]. A First Name tab displays the recipient's first name. The system automatically populates this field by splitting the name in the recipient information on spaces. This value can't be set. [firstName]: /docs/esign-rest-api/reference/envelopes/enveloperecipienttabs/create/#parameters_firstname", OriginalName = "firstNameTabs")]
    public List<FirstName> FirstNameTabs { get; set; }

    [OSStructureField(Description = "A list of [Formula tabs][formulaTab]. The value of a Formula tab is calculated from the values of other number or date tabs in the document. When the recipient completes the underlying fields, the Formula tab calculates and displays the result. This value can be set. The `formula` property of the tab contains the references to the underlying tabs. To learn more about formulas, see [Calculated Fields][calculatedfields]. If a Formula tab contains a `paymentDetails` property, the tab is considered a payment item. To learn more about payments, see [Requesting Payments Along with Signatures][paymentguide]. [calculatedfields]: https://support.docusign.com/s/document-item?bundleId=gbo1643332197980&topicId=crs1578456361259.html [paymentguide]:     https://support.docusign.com/s/document-item?bundleId=juu1573854950452&topicId=fyw1573854935374.html [formulaTab]:       /docs/esign-rest-api/reference/envelopes/enveloperecipienttabs/", OriginalName = "formulaTabs")]
    public List<FormulaTab> FormulaTabs { get; set; }

    [OSStructureField(Description = "A list of [Full Name tabs][fullName]. A Full Name tab displays the recipient's full name. This value can't be set. [fullName]: /docs/esign-rest-api/reference/envelopes/enveloperecipienttabs/", OriginalName = "fullNameTabs")]
    public List<FullName> FullNameTabs { get; set; }

    [OSStructureField(Description = "A list of [Initial Here tabs][initialHere]. This type of tab enables the recipient to initial the document. May be optional. This value can't be set. [initialHere]: /docs/esign-rest-api/reference/envelopes/enveloperecipienttabs/", OriginalName = "initialHereTabs")]
    public List<InitialHere> InitialHereTabs { get; set; }

    [OSStructureField(Description = "A list of [Last Name tabs][lastName]. A Last Name tab displays the recipient's last name. The system automatically populates this field by splitting the name in the recipient information on spaces. This value can't be set. [lastName]: /docs/esign-rest-api/reference/envelopes/enveloperecipienttabs/", OriginalName = "lastNameTabs")]
    public List<LastName> LastNameTabs { get; set; }

    [OSStructureField(Description = "An array of List tabs. A List tab enables the recipient to choose from a list of options. You specify the options in the `listItems` property. This value can't be set. Find descriptions of all tab types in the [EnvelopeRecipientTabs Resource][ert]. [ert]: /docs/esign-rest-api/reference/envelopes/enveloperecipienttabs/", OriginalName = "listTabs")]
    public List<List> ListTabs { get; set; }

    [OSStructureField(Description = "A list of  [Notarize tabs][notarize]. A Notarize tab alerts notary recipients that they must take action on the page. This value can be set. **Note:** Only one notarize tab can appear on a page. [notarize]: /docs/esign-rest-api/reference/envelopes/enveloperecipienttabs/", OriginalName = "notarizeTabs")]
    public List<Notarize> NotarizeTabs { get; set; }

    [OSStructureField(Description = "A list of Notary Seal tabs. A Notary Seal tab enables the recipient to notarize a document. This tab can only be assigned to a remote notary recipient using [Docusign Notary][notary]. [notary]: /docs/notary-api/", OriginalName = "notarySealTabs")]
    public List<NotarySeal> NotarySealTabs { get; set; }

    [OSStructureField(Description = "A list of [Note tabs][note]. A Note tab displays additional information to the recipient in the form of a note. This value can be set. [note]: /docs/esign-rest-api/reference/envelopes/enveloperecipienttabs/", OriginalName = "noteTabs")]
    public List<Note> NoteTabs { get; set; }

    [OSStructureField(Description = "A list of Number tabs. Number tabs validate that the entered value is a number. They do not support advanced validation or display options. To learn more about the different forms of number tabs, see [Number fields](/docs/esign-rest-api/esign101/concepts/tabs/number-fields/) in the Concepts guide. For specific information about number tabs see [Features of numberTabs](/docs/esign-rest-api/esign101/concepts/tabs/number-fields/#features-of-numbertabs). [number]: /docs/esign-rest-api/reference/envelopes/enveloperecipienttabs/", OriginalName = "numberTabs")]
    public List<Number> NumberTabs { get; set; }

    [OSStructureField(Description = "A list of numerical tabs. Numerical  tabs provide robust display and validation features, including formatting for different regions and currencies, and minimum and maximum value validation. To learn more about the different forms of number tabs, see [Number fields](/docs/esign-rest-api/esign101/concepts/tabs/number-fields/) in the Concepts guide. For specific information about numerical tabs see [Features of numericalTabs](/docs/esign-rest-api/esign101/concepts/tabs/number-fields/#features-of-numericaltabs).", OriginalName = "numericalTabs")]
    public List<Numerical> NumericalTabs { get; set; }

    [OSStructureField(Description = "A list of [Phone Number tabs][cc]. A Phone Number tab enables a recipient to enter a phone number. **Note:** This tab can only be assigned to a remote notary recipient using [Docusign Notary][notary]. [cc]:  /docs/esign-rest-api/reference/envelopes/enveloperecipienttabs/ [notary]: /docs/notary-api/", OriginalName = "phoneNumberTabs")]
    public List<PhoneNumber> PhoneNumberTabs { get; set; }

    [OSStructureField(Description = "This type of tab enables the recipient to strike through document text. This value can't be set.", OriginalName = "polyLineOverlayTabs")]
    public List<PolyLineOverlay> PolyLineOverlayTabs { get; set; }

    [OSStructureField(Description = "Maps the 'prefillTabs' field.", OriginalName = "prefillTabs")]
    public PrefillTabs? PrefillTabs { get; set; }

    [OSStructureField(Description = "A list of [Radio Group tabs][radioGroup]. A Radio Group tab places a group of radio buttons on a document. The `radios` property is used to add and place the radio buttons associated with the group. Only one radio button can be selected in a group. This value can be set. [radioGroup]: /docs/esign-rest-api/reference/envelopes/enveloperecipienttabs/", OriginalName = "radioGroupTabs")]
    public List<RadioGroup> RadioGroupTabs { get; set; }

    [OSStructureField(Description = "A list of [Signer Attachment tabs][signerAttachment]. This type of tab enables the recipient to attach supporting documents to an envelope. This value can't be set. [signerAttachment]: /docs/esign-rest-api/reference/envelopes/enveloperecipienttabs/", OriginalName = "signerAttachmentTabs")]
    public List<SignerAttachment> SignerAttachmentTabs { get; set; }

    [OSStructureField(Description = "A list of [Sign Here tabs][signHere]. This type of tab enables the recipient to sign a document. May be optional. This value can't be set. [signHere]: /docs/esign-rest-api/reference/envelopes/enveloperecipienttabs/", OriginalName = "signHereTabs")]
    public List<SignHere> SignHereTabs { get; set; }

    [OSStructureField(Description = "A list of [Smart Section](https://www.docusign.com/blog/dsdev-deep-dive-responsive-smart-sections) tabs. Smart Section tabs enhance responsive signing on mobile devices by enabling collapsible sections, page breaks, custom formatting options, and other advanced functionality. **Note:** Smart Sections are a premium feature. Responsive signing must also be enabled for your account.", OriginalName = "smartSectionTabs")]
    public List<SmartSection> SmartSectionTabs { get; set; }

    [OSStructureField(Description = "A list of [SSN tabs][ssn]. An SSN tab contains a one-line field that enables the recipient to enter a Social Security Number (SSN) with or without dashes. It uses the same parameters as a Text tab, with the validation message and pattern set for SSN information. This value can be set. [ssn]: /docs/esign-rest-api/reference/envelopes/enveloperecipienttabs/", OriginalName = "ssnTabs")]
    public List<Ssn> SsnTabs { get; set; }

    [OSStructureField(Description = "An array of `tabGroup` items. To associate a tab with a tab group, add the tab group's `groupLabel` to the tab's `tabGroupLabels` array.", OriginalName = "tabGroups")]
    public List<TabGroup> TabGroups { get; set; }

    [OSStructureField(Description = "A list of Text tabs. A text tab enables the recipient to enter free text. This value can be set. Find descriptions of all tab types in the [EnvelopeRecipientTabs Resource][ert]. [ert]: /docs/esign-rest-api/reference/envelopes/enveloperecipienttabs/", OriginalName = "textTabs")]
    public List<Text> TextTabs { get; set; }

    [OSStructureField(Description = "A list of [Title tabs][title]. A Title tab displays the recipient's title.  This value can't be set. [title]: /docs/esign-rest-api/reference/envelopes/enveloperecipienttabs/", OriginalName = "titleTabs")]
    public List<Title> TitleTabs { get; set; }

    [OSStructureField(Description = "A list of [View tabs][view]. A View tab is used with an Approve tab to handle supplemental documents.  This value can be set. [view]: /docs/esign-rest-api/reference/envelopes/enveloperecipienttabs/", OriginalName = "viewTabs")]
    public List<View> ViewTabs { get; set; }

    [OSStructureField(Description = "A list of [Zip tabs][zip]. A Zip tab enables the recipient to enter a ZIP code. The ZIP code can be five digits or nine digits ( in ZIP+4 format), and can be entered with or without dashes. It uses the same parameters as a Text tab, with the validation message and pattern set for ZIP code information.  This value can be set. [zip]: /docs/esign-rest-api/reference/envelopes/enveloperecipienttabs/", OriginalName = "zipTabs")]
    public List<Zip> ZipTabs { get; set; }

}

