[OSStructure(Description = "Represents the request body for ResponsiveHtmlPostResponsiveHtmlPreview.")]
public struct ResponsiveHtmlPostResponsiveHtmlPreviewRequest
{
    [OSStructureField(Description = "Contains text that all display anchors must start with. Using at least four characters will improve anchor processing performance.", OriginalName = "displayAnchorPrefix")]
    public string? DisplayAnchorPrefix { get; set; }

    [OSStructureField(Description = "An object that defines how to handle a section of the HTML in signing. This property enables an incoming request to make a section of the HTML collapsible and expandable or hidden from view. A start anchor, end anchor, or both are required. If the anchors are not found, the display anchor will be ignored. For a list of the available types, see the [`display` property](/docs/esign-rest-api/reference/envelopes/envelopes/create/#schema__envelopedefinition_documents_htmldefinition_displayanchors_displaysettings_display) of the [`displaySettings` object.](/docs/esign-rest-api/reference/envelopes/envelopes/create/#schema__envelopedefinition_documents_htmldefinition_displayanchors_displaysettings)", OriginalName = "displayAnchors")]
    public List<DocumentHtmlDisplayAnchor> DisplayAnchors { get; set; }

    [OSStructureField(Description = "The position on the page where the display section appears.", OriginalName = "displayOrder")]
    public string? DisplayOrder { get; set; }

    [OSStructureField(Description = "The number of the page on which the display section appears.", OriginalName = "displayPageNumber")]
    public string? DisplayPageNumber { get; set; }

    [OSStructureField(Description = "The GUID of the document.", OriginalName = "documentGuid")]
    public string? DocumentGuid { get; set; }

    [OSStructureField(Description = "Specifies the document ID number that the tab is placed on. This must refer to an existing Document's ID attribute.", OriginalName = "documentId")]
    public string? DocumentId { get; set; }

    [OSStructureField(Description = "Header text or an HTML tag to place above the responsive HTML block.", OriginalName = "headerLabel")]
    public string? HeaderLabel { get; set; }

    [OSStructureField(Description = "If set, the responsive HTML version of the signing document will only display on screens with the specified pixel width or less. If the screen is larger than the value that you specify, the default PDF version of the content displays instead. This setting can also be configured at the account level.", OriginalName = "maxScreenWidth")]
    public string? MaxScreenWidth { get; set; }

    [OSStructureField(Description = "Holds a comma-separated list of HTML tags to remove if they have no text within their node (including child nodes).", OriginalName = "removeEmptyTags")]
    public string? RemoveEmptyTags { get; set; }

    [OSStructureField(Description = "When **true** (the default), the **Mobile-Friendly** toggle displays at the top of the screen on the user's mobile device. When **false,** the toggle will not be displayed. the **Mobile-Friendly** toggle lets the user switch between the mobile-friendly and the PDF versions of a document. For example, the recipient can use this toggle to review the document using the PDF view before they finish signing.", OriginalName = "showMobileOptimizedToggle")]
    public string? ShowMobileOptimizedToggle { get; set; }

    [OSStructureField(Description = "Specifies the type of responsive signing that will be used with the document. If the value of this property is valid HTML, and the [smart sections feature][] is enabled, the HTML code is used to display the signing page: ``` source: \"<html> ... <body><p>hello world</p></body></html>\" ``` If the value of this property is the string `document`, the HTML signing page is generated from the provided document. ``` source: \"document\" ``` **Related topics** - [How to create a signable HTML document](/docs/esign-rest-api/how-to/creating-signable-html/) - [How to convert a PDF file into a signable HTML document](/docs/esign-rest-api/how-to/converting-pdf/) - [Responsive signing](/docs/esign-rest-api/esign101/concepts/responsive/) [smart sections feature]: https://support.docusign.com/s/document-item?bundleId=gbo1643332197980&topicId=qlx1578456478178.html", OriginalName = "source")]
    public string? Source { get; set; }

}

