[OSStructure(Description = "Represents the request body for ViewsPostEnvelopeCorrectView.")]
public struct ViewsPostEnvelopeCorrectViewRequest
{
    [OSStructureField(Description = "**Required** Identifies the return point after sending the envelope. Docusign returns to the URL and includes an event parameter that can be used to redirect the recipient to another location. The possible event parameters returned are: * send (user sends the envelope) * save (user saves the envelope) * cancel (user cancels the sending transaction. No envelopeId is returned in this case.) * error (there is an error when performing the send) * sessionEnd (the sending session ends before the user completes another action).", OriginalName = "returnUrl")]
    public string? ReturnUrl { get; set; }

    [OSStructureField(Description = "Maps the 'settings' field.", OriginalName = "settings")]
    public EnvelopeViewSettings? Settings { get; set; }

    [OSStructureField(Description = "**Required** . Set to `envelope`", OriginalName = "viewAccess")]
    public string? ViewAccess { get; set; }

}

[OSStructure(Description = "Represents the request body for ViewsDeleteEnvelopeCorrectView.")]
public struct ViewsDeleteEnvelopeCorrectViewRequest
{
    [OSStructureField(Description = "", OriginalName = "beginOnTagger")]
    public string? BeginOnTagger { get; set; }

    [OSStructureField(Description = "(Required) The URL to which the user should be redirected after the view session has ended. Maximum Length: 470 characters. If the `returnUrl` exceeds this limit, the user is redirected to a truncated URL Be sure to include `https://` in the URL or redirecting might fail on some browsers. When Docusign redirects to this URL, it will include an `event` query parameter that your app can use: * `send`: User corrected and sent the envelope. * `save`: User saved the envelope. * `cancel`: User canceled the transaction. * `error`: There was an error when performing the correct or send. * `sessionEnd`: The session ended before the user completed a different action.", OriginalName = "returnUrl")]
    public string? ReturnUrl { get; set; }

    [OSStructureField(Description = "Specifies whether the window is displayed with or without dressing.", OriginalName = "suppressNavigation")]
    public string? SuppressNavigation { get; set; }

    [OSStructureField(Description = "", OriginalName = "viewUrl")]
    public string? ViewUrl { get; set; }

}

