[OSStructure(Description = "Represents the request body for ViewsPostEnvelopeRecipientView.")]
public struct ViewsPostEnvelopeRecipientViewRequest
{
    [OSStructureField(Description = "A unique identifier of the authentication event executed by the client application.", OriginalName = "assertionId")]
    public string? AssertionId { get; set; }

    [OSStructureField(Description = "A sender-generated value that indicates the date and time that the signer was authenticated.", OriginalName = "authenticationInstant")]
    public string? AuthenticationInstant { get; set; }

    [OSStructureField(Description = "Required. Choose a value that most closely matches the technique your application used to authenticate the recipient / signer. Choose a value from this list: * Biometric * Email * HTTPBasicAuth * Kerberos * KnowledgeBasedAuth * None * PaperDocuments * Password * RSASecureID * SingleSignOn_CASiteminder * SingleSignOn_InfoCard * SingleSignOn_MicrosoftActiveDirectory * SingleSignOn_Other * SingleSignOn_Passport * SingleSignOn_SAML * Smartcard * SSLMutualAuth * X509Certificate This information is included in the Certificate of Completion.", OriginalName = "authenticationMethod")]
    public string? AuthenticationMethod { get; set; }

    [OSStructureField(Description = "Maps the 'clientURLs' field.", OriginalName = "clientURLs")]
    public RecipientTokenClientURLs? ClientURLs { get; set; }

    [OSStructureField(Description = "A sender-created value. If provided, the recipient is treated as an embedded (captive) recipient or signer. Use your application's client ID (user ID) for the recipient. Doing so enables the details of your application's authentication of the recipient to be connected to the recipient's signature if the signature is disputed or repudiated. Maximum length: 100 characters.", OriginalName = "clientUserId")]
    public string? ClientUserId { get; set; }

    [OSStructureField(Description = "", OriginalName = "displayFormat")]
    public string? DisplayFormat { get; set; }

    [OSStructureField(Description = "(Required) Specifies the email of the recipient. You can use either `email` and `userName` or `userId` to identify the recipient.", OriginalName = "email")]
    public string? Email { get; set; }

    [OSStructureField(Description = "An array of ancestors that can embed the frame. This property is required when [using focus view](/docs/esign-rest-api/how-to/request-signature-focused-view/). In the demo environment, include your site URL and `https://apps-d.docusign.com`. You can use `http://localhost` for local development and testing. Example: `[\"https://my.site.com\", \"https://apps-d.docusign.com\"]` In the production environment, include your site URL and `https://apps.docusign.com`. HTTPS must be enabled on your site. Example:  `[\"https://my.site.com\", \"https://apps.docusign.com\"]`", OriginalName = "frameAncestors")]
    public List<string> FrameAncestors { get; set; }

    [OSStructureField(Description = "The originating domain for the signature request message. This property is required when [using focus view](/docs/esign-rest-api/how-to/request-signature-focused-view/). In the demo environment, the value must be `https://apps-d.docusign.com`. In production, the value must be `https://apps.docusign.com`.", OriginalName = "messageOrigins")]
    public List<string> MessageOrigins { get; set; }

    [OSStructureField(Description = "Only used if `pingUrl` is specified. This is the interval, in seconds, between pings on the `pingUrl`.  The default is `300` seconds. Valid values are 60-1200 seconds.", OriginalName = "pingFrequency")]
    public string? PingFrequency { get; set; }

    [OSStructureField(Description = "The client URL that the Docusign Signing experience should ping to indicate to the client that Signing is active. An HTTP GET call is executed against the client. The response from the client is ignored. The intent is for the client to reset its session timer when the request is received.", OriginalName = "pingUrl")]
    public string? PingUrl { get; set; }

