    [OSStructureField(Description = "A list of [Note tabs][note]. A Note tab displays additional information to the recipient in the form of a note. This value can be set. [note]: /docs/esign-rest-api/reference/envelopes/enveloperecipienttabs/", OriginalName = "noteTabs")]
    public List<Note> NoteTabs { get; set; }

