    public List<Text> TextTabs { get; set; }

    [OSStructureField(Description = "A list of [Title tabs][title]. A Title tab displays the recipient's title.  This value can't be set. [title]: /docs/esign-rest-api/reference/envelopes/enveloperecipienttabs/", OriginalName = "titleTabs")]
